}

div.panel.panel-.b {
  position: relative;
}

//---------------------------------------------------------------------------------
//KT Wrapping Table Headers
// 2.8.1 | 2023-03-20 | mmcc | STRY0136039 - State Chevron Breakpoints to prevent Wrapping Text; OOTB Data Table CSS has .th-title
.v5001b062d7101200b0b044580e6103eb .th-title {
  display: inline-block;
  color: $primary;
  //KT
  white-space: normal;
}

/*
2.8.1 | 2023-03-20 | mmcc | STRY0136039 - State Chevron Breakpoints to prevent Wrapping Text; remove override
.text-nowrap {
  white-space: normal;
} 
*/

//KT Disable Filter Link
.v339a5c41d7201200b0b044580e61030d .breadcrumbs {
	pointer-events: none;
  cursor: default;
  text-decoration:none;
  color: black;
}
//---------------------------------------------------------------------------------


// each column has a flex-item classs
.flex-item {
  width: 50%;
  position: relative;
  margin: 5px;
}

.panel {
  position: absolute;
  top: 0;
  bottom: 0;
  right: 0;
  left: 0;
  margin: 0;
  overflow: hidden;
  border-radius: 0;
  // flexbox
  display: flex; 
  flex-direction: column;

 
  .panel-body {
    overflow: scroll;
    -webkit-overflow-scrolling: touch;
    flex-grow: 1;
    padding-top: 2px; //30px; 
  }

  .panel-heading, .panel-footer {
    flex-shrink: 0;
  }

  .panel-heading {
    height: 100px;//52px;
  }
}

.panel.ticket_conversation, .modal-body .panel {
  position: relative;
  display: block;
  border-radius: 4px;
  
  .panel-body {
    overflow: auto;
  }
}
